package cli

import (
	"fmt"
	"math"
	"strings"
	"time"

	"github.com/spf13/cobra"
	"github.com/mvanhorn/printing-press-library/library/commerce/shopper/internal/cliutil"
	"github.com/mvanhorn/printing-press-library/library/commerce/shopper/internal/store"
)

type shrinkflationItem struct {
	ProductID     string  `json:"product_id"`
	Name          string  `json:"name"`
	OldPriceCents int64   `json:"old_price_cents"`
	NewPriceCents int64   `json:"new_price_cents"`
	OldPackGrams  int64   `json:"old_pack_grams"`
	NewPackGrams  int64   `json:"new_pack_grams"`
	OldRsPerKg    float64 `json:"old_rs_per_kg"`
	NewRsPerKg    float64 `json:"new_rs_per_kg"`
	UnitInflation float64 `json:"unit_inflation_pct"`
	DetectedAt    string  `json:"detected_at"`
}

type discontinuedItem struct {
	ProductID  string  `json:"product_id"`
	Name       string  `json:"name"`
	LastSeenAt string  `json:"last_seen_at"`
	LastPrice  float64 `json:"last_price"`
}

type catalogDriftResult struct {
	Status        string              `json:"status"`
	Note          string              `json:"note,omitempty"`
	Metric        string              `json:"metric"`
	Since         string              `json:"since"`
	Shrinkflation []shrinkflationItem `json:"shrinkflation"`
	Discontinued  []discontinuedItem  `json:"discontinued"`
}

func newNovelCatalogDriftCmd(flags *rootFlags) *cobra.Command {
	var flagMetric string
	var flagKind string
	var flagSince string

	cmd := &cobra.Command{
		Use:     "drift",
		Short:   "Flags products you buy that were discontinued, silently swapped, or kept their price while shrinking the pack",
		Example: "  shopper-pp-cli catalog drift --since 90d --kind shrinkflation,discontinued --json",
		Long: `Analyzes price_snapshots to detect:

  shrinkflation  Same or higher price but smaller pack size → higher R$/unit cost.
  discontinued   A previously-basket-snapshotted SKU that no longer appears in
                 catalog search results.

  --metric    Unit metric to use for per-unit price (default: per-unit).
              "per-unit" uses R$/gram (or R$/ml) derived from pack-size parsing.
  --kind      Comma-separated list of detection types: shrinkflation,discontinued
              (default: both).
  --since     Lookback window (default: 90d).

HONEST DEGRADATION: Requires accumulated price_snapshots (built by running
price-watch repeatedly). Shrinkflation detection requires products with parseable
pack sizes in their names (e.g. "Arroz 5KG", "Leite 1L").`,
		Annotations: map[string]string{
			"mcp:read-only":          "true",
			"pp:no-error-path-probe": "true",
		},
		RunE: func(cmd *cobra.Command, args []string) error {
			if len(args) == 0 && cmd.Flags().NFlag() == 0 {
				return cmd.Help()
			}
			if dryRunOK(flags) {
				fmt.Fprintln(cmd.OutOrStdout(), `{"dry_run":true,"would":"analyze price_snapshots for shrinkflation and discontinued items"}`)
				return nil
			}

			// Parse --since
			sinceStr := flagSince
			if sinceStr == "" {
				sinceStr = "90d"
			}
			sinceDur, err := cliutil.ParseDurationLoose(sinceStr)
			if err != nil {
				return usageErr(fmt.Errorf("invalid --since %q: %w", flagSince, err))
			}
			sinceTime := time.Now().Add(-sinceDur)

			// Parse --kind
			if flagKind == "" {
				flagKind = "shrinkflation,discontinued"
			}
			kindSet := make(map[string]bool)
			for _, k := range strings.Split(flagKind, ",") {
				kindSet[strings.TrimSpace(k)] = true
			}

			if flagMetric == "" {
				flagMetric = "per-unit"
			}

			// Open local store
			db, err := store.OpenWithContext(cmd.Context(), defaultDBPath("shopper-pp-cli"))
			if err != nil {
				return fmt.Errorf("opening local store: %w", err)
			}
			defer db.Close()

			// Load price snapshots within window
			snaps, err := store.PriceSnapshotWindow(db.DB(), sinceTime, nil)
			if err != nil {
				return fmt.Errorf("reading price snapshots: %w", err)
			}

			result := catalogDriftResult{
				Metric:        flagMetric,
				Since:         sinceTime.Format("2006-01-02"),
				Shrinkflation: make([]shrinkflationItem, 0),
				Discontinued:  make([]discontinuedItem, 0),
			}

			if len(snaps) == 0 {
				result.Status = "insufficient_history"
				result.Note = "No price snapshots found for the selected window. Run 'price-watch' first to accumulate price history."
				return printJSONFiltered(cmd.OutOrStdout(), result, flags)
			}

			// Group snapshots by product ID: first and last within window
			type productHistory struct {
				earliest store.PriceSnapshot
				latest   store.PriceSnapshot
			}
			byProduct := make(map[string]*productHistory)
			for _, s := range snaps {
				ph := byProduct[s.ProductID]
				if ph == nil {
					ph = &productHistory{earliest: s, latest: s}
					byProduct[s.ProductID] = ph
				} else {
					if s.TakenAt.Before(ph.earliest.TakenAt) {
						ph.earliest = s
					}
					if s.TakenAt.After(ph.latest.TakenAt) {
						ph.latest = s
					}
				}
			}

			// Detect shrinkflation
			if kindSet["shrinkflation"] {
				for _, ph := range byProduct {
					if ph.earliest.ID == ph.latest.ID {
						continue // only one point
					}
					oldGrams := ph.earliest.PackGrams
					newGrams := ph.latest.PackGrams
					if oldGrams <= 0 || newGrams <= 0 {
						continue // can't compare without pack size
					}
					// Pack shrunk?
					if newGrams >= oldGrams {
						continue
					}
					oldPriceCents := ph.earliest.PriceCents
					newPriceCents := ph.latest.PriceCents
					if oldPriceCents <= 0 || newPriceCents <= 0 {
						continue
					}
					oldRsPerKg := float64(oldPriceCents) / float64(oldGrams) * 10 // cents/g → R$/kg
					newRsPerKg := float64(newPriceCents) / float64(newGrams) * 10
					unitInflation := (newRsPerKg - oldRsPerKg) / oldRsPerKg * 100
					if unitInflation <= 0 {
						continue
					}
					result.Shrinkflation = append(result.Shrinkflation, shrinkflationItem{
						ProductID:     ph.latest.ProductID,
						Name:          ph.latest.Name,
						OldPriceCents: oldPriceCents,
						NewPriceCents: newPriceCents,
						OldPackGrams:  oldGrams,
						NewPackGrams:  newGrams,
						OldRsPerKg:    math.Round(oldRsPerKg*100) / 100,
						NewRsPerKg:    math.Round(newRsPerKg*100) / 100,
						UnitInflation: math.Round(unitInflation*100) / 100,
						DetectedAt:    ph.latest.TakenAt.Format("2006-01-02"),
					})
				}
			}

			// Detect discontinued: basket SKUs in snapshots but not currently in catalog
			if kindSet["discontinued"] {
				// Load cart snapshots to know which products are in the basket
				cartSnaps, cerr := store.LatestCartSnapshots(db.DB(), 1)
				if cerr == nil && len(cartSnaps) > 0 {
					// Products ever tracked in price_snapshots
					basketProductIDs := make(map[string]bool)
					for _, item := range cartSnaps[0].Items {
						basketProductIDs[item.ID] = true
					}

					// A product is "discontinued" if it was tracked before but is
					// absent from the most recent catalog-snapshot run, while other
					// products WERE captured in that run. This is relative to the
					// latest run — not an absolute wall-clock cutoff — so a user who
					// runs price-watch weekly doesn't see their whole basket flagged.
					const runWindow = time.Hour
					var globalLatest, oldest time.Time
					latestSeenAt := make(map[string]store.PriceSnapshot)
					for _, s := range snaps {
						if s.TakenAt.After(globalLatest) {
							globalLatest = s.TakenAt
						}
						if oldest.IsZero() || s.TakenAt.Before(oldest) {
							oldest = s.TakenAt
						}
						ls, exists := latestSeenAt[s.ProductID]
						if !exists || s.TakenAt.After(ls.TakenAt) {
							latestSeenAt[s.ProductID] = s
						}
					}
					latestRunCutoff := globalLatest.Add(-runWindow)
					inLatestRun := make(map[string]bool)
					for _, s := range snaps {
						if !s.TakenAt.Before(latestRunCutoff) {
							inLatestRun[s.ProductID] = true
						}
					}
					// Discontinuation is only determinable when at least two distinct
					// capture runs exist (a newer run that could have re-observed the item).
					multipleRuns := globalLatest.Sub(oldest) >= runWindow && len(inLatestRun) > 0

					if multipleRuns {
						for id := range basketProductIDs {
							ls, seen := latestSeenAt[id]
							if seen && !inLatestRun[id] {
								result.Discontinued = append(result.Discontinued, discontinuedItem{
									ProductID:  id,
									Name:       ls.Name,
									LastSeenAt: ls.TakenAt.Format("2006-01-02"),
									LastPrice:  float64(ls.PriceCents) / 100,
								})
							}
						}
					}
				}
			}

			hasFindings := len(result.Shrinkflation) > 0 || len(result.Discontinued) > 0
			if !hasFindings {
				result.Status = "no_drift"
				result.Note = fmt.Sprintf("No catalog drift detected across %d tracked products since %s. "+
					"Shrinkflation detection requires products with parseable pack sizes in their names (e.g. '5KG', '1L').",
					len(byProduct), sinceTime.Format("2006-01-02"))
			} else {
				result.Status = "drift_detected"
			}

			// Emit JSON regardless of terminal status (this is an analytics command)
			return printJSONFiltered(cmd.OutOrStdout(), result, flags)
		},
	}
	cmd.Flags().StringVar(&flagMetric, "metric", "per-unit", "Unit metric for comparison: per-unit (R$/g or R$/ml)")
	cmd.Flags().StringVar(&flagKind, "kind", "shrinkflation,discontinued", "Detection types: shrinkflation,discontinued")
	cmd.Flags().StringVar(&flagSince, "since", "90d", "Lookback window for comparisons (e.g. 90d, 6w)")
	return cmd
}
